rss.channel:

    {{ .Site.Title | htmlEscape }}
    {{ .Site.BaseURL | htmlEscape }}

    Recent content on {{ .Site.Title | htmlEscape }}


    {{ range first 20 (where .Site.RegularPages "Section" "posts") }}
    {{ if not .Params.noSitemap }}


      {{ .Title | plainify | htmlEscape }}
      {{ .Permalink | htmlEscape }}
      {{ .Permalink | htmlEscape }}


      {{ with .Params.categories }}{{ range . }}{{ . | plainify | htmlEscape }}{{ end }}{{ end }}
      {{ with .Params.tags }}{{ range . }}{{ . | plainify | htmlEscape }}{{ end }}{{ end }}

      {{/* 🖼️ FEATURED IMAGES */}}
      {{ $imgStr := .Params.thumbnail | default (index .Params.images 0) }}
      {{ $imgHtml := "" }}
      {{ if $imgStr }}
        {{ $res := resources.Get $imgStr }}
        {{ if $res }}
          {{ $optimized := $res.Resize "800x webp q80" }}


          {{ $imgHtml = printf "
" $optimized.Permalink (.Title | plainify | htmlEscape) }}
        {{ else }}


          {{ $imgHtml = printf "
" ($imgStr | absURL | htmlEscape) (.Title | plainify | htmlEscape) }}
        {{ end }}
      {{ end }}

      {{/* 🧹 HYPER-AGGRESSIVE CLEANUP PIPELINE */}}
      {{ $cleanContent := .Content }}
      {{ $cleanContent = $cleanContent | replaceRE "(?is)\\s*
Source:.*" "" }}
      {{ $cleanContent = $cleanContent | replaceRE "(?is)<hr class=\"my-5\".*" "" }}
      {{ $cleanContent = $cleanContent | replaceRE "(?is)
]*id=\"discussion-title\".*" "" }}
      {{ $cleanContent = $cleanContent | replaceRE "(?is)
]*id=\"login-ui\".*" "" }}
      {{ $cleanContent = $cleanContent | replaceRE "(?is)]*aria-labelledby[^>]*>.*?" "" }}
      {{ $cleanContent = $cleanContent | replaceRE "(?is)<svg.*?" "" }}
      {{ $cleanContent = $cleanContent | replaceRE "(?is)<script.*?" "" }}
      {{ $cleanContent = $cleanContent | replaceRE "(?is)<style.*?" "" }}
      {{ $cleanContent = $cleanContent | replaceRE "\\s+(id|class|style|aria-[a-z]+|role|data-[a-z]+|tabindex)=\"[^\"]*\"" "" }}
      {{ $cleanContent = $cleanContent | replaceRE "(?is)" "" }}

      {{/* FIX 2: No more CDATA. We safely HTML-escape the combined image and content. */}}
      {{ $cleanContent | plainify | htmlEscape }}

      {{/* 🚨 Clean Description */}}
      {{ .Summary | plainify | htmlEscape }}

    {{ end }}
    {{ end }}
